{
  "lessons": [
    {
      "concepts": [
        "Sambaquis (shell mounds)",
        "Marajoara culture pottery",
        "Kuhikugu and Xingu urbanism",
        "Oral traditions",
        "Ethnohistory"
      ],
      "description": "See how archaeologists, indigenous oral traditions, and physical artifacts piece together the complex societies that existed long before written colonial records.",
      "title": "Finding Evidence of Pre-Colonial Brazil"
    },
    {
      "concepts": [
        "Tupi-Guarani coastal expansion",
        "Macro-Jê societies of the central plateau",
        "Arawak and Karib language families",
        "Pre-colonial demographics"
      ],
      "description": "Track the massive migrations and linguistic diversity that shaped the continent, breaking the myth of a single, uniform indigenous culture.",
      "title": "Mapping the Tupi, Macro-Jê, and Amazonian Peoples"
    },
    {
      "concepts": [
        "Terra Preta (Amazonian dark earth)",
        "Bitter manioc cultivation",
        "Agroforestry and forest management",
        "The Peabiru trail network"
      ],
      "description": "Trace how Indigenous communities engineered the Amazon with fertile dark earth, domesticated vital crops, and moved goods across continent-spanning pathways.",
      "title": "Engineering the Landscape and Trading Across Land"
    },
    {
      "concepts": [
        "Malocas and village layout",
        "Pajés (shamans) and animism",
        "Tupinambá warfare",
        "Ritual anthropophagy"
