  ]
}

{
  "lessons": [
    {
      "concepts": [
        "Métricas de fluxo vs. rastreamento de horas",
        "Otimização do sistema vs. desempenho individual",
        "Segurança psicológica na análise de dados"
      ],
      "description": "Mude o foco de quem está trabalhando para como o trabalho flui. Compare métricas que expõem gargalos no sistema com aquelas que apenas medem esforço individual.",
      "title": "Avaliando o fluxo sem punir pessoas"
    },
    {
      "concepts": [
        "Ponto de compromisso e ponto de entrega",
        "Customer Lead Time (visão do cliente)",
        "System Cycle Time (visão do processo)",
        "Métricas de resultado (Lagging indicators)"
      ],
      "description": "Identifique onde o relógio começa e termina para cada métrica de tempo. Diferencie a expectativa de espera do cliente do tempo real de execução da equipe.",
      "title": "Medindo o tempo com Lead Time e Cycle Time"
    },
    {
      "concepts": [
        "Work in Progress (WIP)",
        "Taxa de vazão (Throughput)",
        "A relação matemática básica (Lei de Little)",
        "O impacto do excesso de trabalho na vazão"
      ],
      "description": "Conte quantos itens estão no sistema e quantos são entregues por período. Descubra por que iniciar mais tarefas não significa necessariamente entregar mais resultados.",
      "title": "Avaliando volume de trabalho com WIP e Throughput"
    },
    {
      "concepts": [
        "Idade do item (Work Item Age)",
        "Indicadores antecedentes (Leading indicators)",
        "Decisões táticas baseadas no envelhecimento",
        "Priorização de conclusão de itens antigos"
      ],
      "description": "Use a única métrica do Kanban que foca no presente. Acompanhe o envelhecimento dos cartões ativos para destravar o trabalho antes que ele atrase ou vire um problema.",
      "title": "Agindo antes do atraso com a Idade do Item"
    }
  ]
}

{
